			if err != nil {
				return apis.NewInternalServerError("failed to generate presigned URL", err)
			}

			return e.JSON(http.StatusOK, map[string]string{
				"url": presignResult.URL,
			})
		})

		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}
